//조회 조건 초기화
scwin.f_FieldClear = function (e) {
    ed_cnd_odrNo.setValue("")
    ed_cnd_cntrNo.setValue("")
};

//조회
scwin.f_Retrieve = async function () {
    if (ed_cnd_odrNo.getValue().trim() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["오더번호"]); //@은(는) 필수 입력 항목입니다.
        return;
    }

    let validataVal = await $c.gus.cfValidate([tbl_cndArea])

    if (validataVal) {
        ds_cndInfo.setEmptyValue();
        ds_cndInfo.set("odrNo", ed_cnd_odrNo.getValue().trim());
        ds_cndInfo.set("cntrNo", ed_cnd_cntrNo.getValue().trim());
        scwin.retrieveYn = "Y";
        $c.sbm.execute(sbm_retrieve); // tr_retrieve.Post();
    }
}

//저장하기전에 값 세팅
//부두간 TS인 경우 : 수입온도를 수출온도에도 세팅해야함
//수입,수출온도구분(sd404)을 온도구분(sd403)으로 세팅
scwin.f_setValueBeforeSave = async function () {
    let odrKndCd = "";
    let cntrInfoRows = ds_cntrInfo.getTotalRow();

    for (let i = 0; i < cntrInfoRows; i++) {
        // 수출신고번호 컬럼명 혼용 보정
        ds_cntrInfo.setCellData(i, "expClarNo", ds_cntrInfo.getCellData(i, "expDeclarNo"));
    }


    if (cntrInfoRows > 0) {
        let rowVal = ds_cntrInfo.getRowPosition();
        odrKndCd = ds_cntrInfo.getCellData(rowVal, "odrKndCd"); //오더종류
        //부두간 TS
        if (odrKndCd == "CT") {
            for (i = 0; i < cntrInfoRows; i++) {
                let impTempVal = ds_cntrInfo.getCellData(i, "impTemper")
                let tempClsVal = ds_cntrInfo.getCellData(i, "impTemperCls")

                ds_cntrInfo.setCellData(i, "expTemper", impTempVal);
                ds_cntrInfo.setCellData(i, "expTemperCls", tempClsVal);
            }
        }

        //수입,수출온도구분(sd404) -> 온도구분(sd403)
        let tempVal;
        for (i = 0; i < cntrInfoRows; i++) {
            let clsCdVal = ds_cntrInfo.getCellData(i, "impExpDomesticClsCd");

            if (clsCdVal == "I"
                && !$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "impTemper"))
                && !$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "impTemperCls"))
                && ds_cntrInfo.getRowStatusValue(i) == 3
                && ds_cntrInfo.getModifiedIndex().length) {
                tempVal = ds_cntrInfo.getCellData(i, "impTemperCls")

            } else if (clsCdVal == "O"
                && !$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "expTemper"))
                && !$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "expTemperCls"))
                && ds_cntrInfo.getModifiedIndex().length) {
                tempVal = ds_cntrInfo.getCellData(i, "expTemperCls")
            }
            ds_cntrInfo.setCellData(i, "temperCls", tempVal);
        }
    }
}

//저장
scwin.f_Save = async function () {

    let confirmVal = await $c.win.confirm(MSG_CM_CRM_001)

    if (confirmVal) { //저장하시겠습니까?
        if (ds_cntrInfo.getModifiedIndex().length) {

            let validataVal = await $c.gus.cfValidate([gr_cntrInfo])
            if (validataVal) {
                await scwin.f_setValueBeforeSave(); //저장하기전에 값세팅
                // $c.sbm.execute(sbm_save); // tr_save.Post();
                await scwin.submitExcute(sbm_save);
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); //@은(는) 변경된 사항이 없습니다.
        }
    }
}

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_save:
            await scwin.sbm_save_submitdone(e)
            break;
        default:
            break;
    }
};

/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {

    const e = await $c.sbm.execute(sbmObj);

    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        if (e.responseJSON.resultDataSet[0].Code == -1) return;
        await scwin.submitdone(e);
    };
};

//행취소
scwin.f_UndoRow = function () {
    if (ds_cntrInfo.getTotalRow() > 0) {
        // ds_cntrInfo.Undo(ds_cntrInfo.rowPosition);
        $c.data.undoRow(ds_cntrInfo, "Y");
    }
}

//조회후에 그리드헤더세팅
scwin.f_SetGridHeader = function (odrNo, impExpClsCd) {

    // 기본
    const DEFAULT_COLUMN_VISIBLE = {
        "cntrNo": true,					 // 컨테이너번호 
        "cntrSizCd": true,        // Size 
        "cntrTypCd": true,       // Type 
        "fullEmptyClsCd": true,         // F/E
        "rmk": true,        	 // 비고 
        "bookingNo": false,
        "expDeclarNo": false,
        "impTemper": true,      // 온도(수입) 
        "impTemperCls": true,  // 온도구분(수입)   
        "impDryYn": true,  // DRY여부(수입)  
        "impWt": true,     // 중량(수입)  
        "impDangerCd": true,  // 위험물코드(수입)  
        "unno": true,       // UNNO  
        "impSealNo": true,// Seal-No(수입)  
        "impOverLength": true,   // 초과길이(수입)  
        "impOverWidTh": true,    // 초과폭(수입)  
        "impOverHeight": true,   // 초과높이(수입)  
        "expTemper": true,     // 온도(수출)  
        "expTemperCls": true,  // 온도구분(수출)   
        "dryYn": true,	 // DRY여부(수출)  
        "expWt": true,     // 중량(수출)  
        "expDangerCd": true,  // 위험물코드(수출)  
        "expSealNo": true,// Seal-No(수출)  
        "expOverLength": true,   // 초과길이(수출)  
        "expOverHeight": true,   // 초과높이(수출)  
        "expOverWidth": true,    // 초과폭(수출)  
        "portCd": true,       // PORT  
        "cntrStsNm": true,         // 상태  
    };

    // 수입
    const IMP_COLUMN_VISIBLE = {
        "cntrNo": true,
        "cntrSizCd": true,
        "cntrTypCd": true,
        "fullEmptyClsCd": true,
        "rmk": true,
        "bookingNo": false,
        "expDeclarNo": false,
        "impTemper": true,
        "impTemperCls": true,
        "impDryYn": true,
        "impWt": true,
        "impDangerCd": true,
        "unno": true,
        "impSealNo": true,
        "impOverLength": true,
        "impOverWidTh": true,
        "impOverHeight": true,
        "expTemper": false,     // 온도(수출)  
        "expTemperCls": false,  // 온도구분(수출)   
        "dryYn": false,	 // DRY여부(수출)  
        "expWt": false,     // 중량(수출)  
        "expDangerCd": false,  // 위험물코드(수출)  
        "expSealNo": false,// Seal-No(수출)  
        "expOverLength": false,   // 초과길이(수출)  
        "expOverHeight": false,   // 초과높이(수출)  
        "expOverWidth": false,    // 초과폭(수출)  
        "portCd": true,
        "cntrStsNm": true,
    };

    // 수출: 수출인 경우, 셔틀인 경우는 수출을 default로 보여줄 것
    const EXP_COLUMN_VISIBLE = {
        "cntrNo": true,
        "cntrSizCd": true,
        "cntrTypCd": true,
        "fullEmptyClsCd": true,
        "rmk": true,
        "bookingNo": true,
        "expDeclarNo": true,
        "impTemper": false,
        "impTemperCls": false,
        "impDryYn": false,
        "impWt": false,
        "impDangerCd": false,
        "unno": false,
        "impSealNo": false,
        "impOverLength": false,
        "impOverWidTh": false,
        "impOverHeight": false,
        "expTemper": true,
        "expTemperCls": true,
        "dryYn": true,
        "expWt": true,
        "expDangerCd": true,
        "expSealNo": true,
        "expOverLength": true,
        "expOverHeight": true,
        "expOverWidth": true,
        "portCd": true,
        "cntrStsNm": true,
    };

    // 그리드 수정하고 확인해야함.
    let COLUMN_VISIBLE = {};
    if (odrNo != null && odrNo != "") {
        COLUMN_VISIBLE = (impExpClsCd == DsConstants.IMP_CD) ? IMP_COLUMN_VISIBLE : EXP_COLUMN_VISIBLE
    } else {
        COLUMN_VISIBLE = DEFAULT_COLUMN_VISIBLE;
    }

    // 조건별 그리드뷰 컬럼 visible 세팅
    Object.keys(COLUMN_VISIBLE).forEach(function (colId) {
        gr_cntrInfo.setColumnVisible(colId, COLUMN_VISIBLE[colId]);
    });

    gr_cntrInfo.redrawColumn();

}

//항구 조회 Popup 처리 : 그리드에서 입력된 코드정보로 항구를 조회
scwin.f_openCommPopUpGrid = function (row, pWinCloseTF, pAllSearchTF, newVal) {
    // 선언부
    let rtnList;  // 공통POP-UP -> 요청화면 
    let pCode = "";
    let pName = "";

    // 품명 코드팝업		
    if(!newVal) pCode = ds_cntrInfo.getCellData(row, "portCd");  // 항구코드
    else pCode = newVal;

    udc_port.setSelectId('retrievePortInfo')
    rtnList = udc_port.cfCommonPopUp((rtnList)=>{
        if(rtnList == undefined || rtnList[0] == 'N/A') return;
        $c.gus.cfSetGridReturnValue(rtnList, ds_cntrInfo, row, "portCd", "portNm");
    },
        pCode,							//pCode
        pName,							//pName
        pWinCloseTF,					//pWinCloseTF
        null,							//pDispCnt
        null,							//pTitle
        null,							//pWidth
        null,							//pHidden
        null,							//pWhere
        null,							//pW
        null,							//pH
        null,							//pTop
        null,							//pLeft
        null,							//pExistTF - 중복체크여부	("F")
        pAllSearchTF,					//pAllSearchTF - 전체검색허용여부	("F")
        "항구,항구코드,항구명",				//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        null							//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
    );

    return false;
}



//컨테이너 type이 'RF'인 경우, 온도와 dry여부 둘 중에 하나만 입력해야 함
scwin.f_SetTemperDryByRFCntr = function (ds, gr, row) {
    let type = ds.getCellData(row, "cntrTypCd");	//컨테이너type
    let impTemper = ds.getCellData(row, "impTemper");	//수입온도
    let impDryYn = ds.getCellData(row, "impDryYn");	//수입dry여부
    let expTemper = ds.getCellData(row, "expTemper");	//수출온도
    let expDryYn = ds.getCellData(row, "dryYn"); 		//수출dry여부

    if (["RF", "RH"].includes(type)) {
        //수입
        if (!$c.gus.cfIsNull(impTemper) && impDryYn == 0) {

            gr_cntrInfo.setCellReadOnly(row, "impTemper", false)
            gr_cntrInfo.setCellReadOnly(row, "impTemperCls", false)
            gr_cntrInfo.setCellReadOnly(row, "impDryYn", true)

        } else if ($c.gus.cfIsNull(impTemper) && impDryYn == 1) {

            gr_cntrInfo.setCellReadOnly(row, "impTemper", true)
            gr_cntrInfo.setCellReadOnly(row, "impTemperCls", true)
            gr_cntrInfo.setCellReadOnly(row, "impDryYn", false)

        } else {

            gr_cntrInfo.setCellReadOnly(row, "impTemper", false);
            gr_cntrInfo.setCellReadOnly(row, "impDryYn", false);
        }

        //수출
        let expTemperBool, expTemperClsBool, dryYnBool;

        if (!$c.gus.cfIsNull(expTemper) && expDryYn == 0) {
            expTemperBool = false;
            expTemperClsBool = false;
            dryYnBool = true;
        } else if ($c.gus.cfIsNull(expTemper) && expDryYn == 1) {
            expTemperBool = true;
            expTemperClsBool = true;
            dryYnBool = false;
        } else {
            expTemperBool = false;
            expTemperClsBool = false;
            dryYnBool = false;
        }

        gr_cntrInfo.setCellReadOnly(row, "expTemper", expTemperBool);
        gr_cntrInfo.setCellReadOnly(row, "expTemperCls", expTemperClsBool);
        gr_cntrInfo.setCellReadOnly(row, "dryYn", dryYnBool);

    } else {
        ds.setCellData(row, "impTemper", "");
        ds.setCellData(row, "impDryYn", 0);
        ds.setCellData(row, "expTemper", "");
        ds.setCellData(row, "dryYn", 0);

        gr_cntrInfo.setCellReadOnly(row, "impTemper", true);
        gr_cntrInfo.setCellReadOnly(row, "impDryYn", true);
        gr_cntrInfo.setCellReadOnly(row, "impTemperCls", true);
        gr_cntrInfo.setCellReadOnly(row, "expTemper", true);
        gr_cntrInfo.setCellReadOnly(row, "dryYn", true);
        gr_cntrInfo.setCellReadOnly(row, "expTemperCls", true);
    }
}


scwin.f_Close = function () {
    if (opener != "undefined") {
        let arrRtnVal = new Array();

        arrRtnVal[0] = "N/A";
        arrRtnVal[1] = scwin.saveYn;
        // window.returnValue = arrRtnVal;
        // window.close();
        $c.win.closePopup(arrRtnVal);
    }
}

// <!-- 컨테이너정보 조회 TR -->         
// for=tr_retrieve event=OnSuccess()
scwin.sbm_retrieve_submitdone = async function (e) {
    let rowCnt = ds_cntrInfo.getTotalRow();
    if (rowCnt > 0) {
        //그리드 세팅 
        // ds_cntrInfo.rowPosition
        scwin.f_SetGridHeader(ds_cndInfo.get("odrNo"), ds_cntrInfo.getCellData(0, "impExpDomesticClsCd"));
        // gr_cntrInfo.ColumnProp('impTemperCls','Data') = ",CEL:[CEL]섭씨,FAH:[FAH]화씨,DRY:[DRY]건조";
        // gr_cntrInfo.ColumnProp('expTemperCls','Data') = ",CEL:[CEL]섭씨,FAH:[FAH]화씨,DRY:[DRY]건조";
        // 그리드 안에 inputtype: select에 이미 설정하여 따로 스크립트로 설정해줄 필요 없음.
        await scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, 0);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, new Array("조회결과"));
    }
    totalRows.setValue(rowCnt)
    scwin.retrieveYn = "N";
};

// <!-- 컨테이너정보 저장 TR -->      
scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.
    scwin.saveYn = "Y"; //팝업으로 띄워졌을때 parent에 보내는 값
    scwin.f_Retrieve();
};

// for=ds_cntrInfo event=OnRowPosChanged(row)
scwin.ds_cntrInfo_onrowpositionchange = function (info) {
    let row = info.newRowIndex;
    if (scwin.retrieveYn == "N") {
        //cfPrepareHidVal(ds_cntrInfo, row, ["portCd", "portNm"]);
        scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, row);
    }
};

scwin.gr_cntrInfo_popup = function (rowIndex, colId, nowValue) {
    // to-do
    switch (colId) {
        case "portCd":
            scwin.f_openCommPopUpGrid(rowIndex, 'F');
            break;
    }
}

// <!-- GRID OnClick : gr_cntrInfo에서 OnClick이벤트 발생시  -->
// for=gr_cntrInfo event=OnClick(row,colid)
scwin.gr_cntrInfo_oncellclick = function (rowIndex, columnIndex, columnId) {

    if (rowIndex > 0) {
        switch (columnId) {
            case "impDryYn": //수입dryYn
                scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
                break;

            case "impTemperCls": //수입오더구분
                scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
                break;

            case "dryYn": //수출dryYn
                scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
                break;
        }
    }
};

// for=gr_cntrInfo event=OnDblClick(row,colid)
scwin.gr_cntrInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    let rowCount = ds_cntrInfo.getTotalRow();
    let val;

    if (columnId == "temperCls") {
        for (let i = 0; i < rowCount; i++) {
            if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "temper"))
                && gr_cntrInfo.editable == true
            ) {
                val = ds_cntrInfo.getCellData(rowIndex, "temperCls")
                ds_cntrInfo.setCellData(i, "temperCls",);
            }
        }
    }
    if (columnId == "impTemperCls") {
        for (let i = 0; i < rowCount; i++) {
            if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "impTemper"))
                && gr_cntrInfo.editable == true
            ) {
                val = ds_cntrInfo.getCellData(rowIndex, "impTemperCls")
                ds_cntrInfo.setCellData(i, "impTemperCls", val);
            }
        }
    }
    if (columnId == "expTemperCls") {
        for (let i = 0; i < rowCount; i++) {
            if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "expTemper"))
                && gr_cntrInfo.editable == true
            ) {
                val = ds_cntrInfo.getCellData(rowIndex, "expTemperCls")
                ds_cntrInfo.setCellData(i, "expTemperCls", val);
            }
        }
    }
};

// <!-- EMEDIT EVENT : 검색조건 ed_lineCd에서 OnKillFocus이벤트 발생시  -->
// for=ed_cnd_odrNo event=OnKeyUp(kcode,scode)
scwin.ed_cnd_odrNo_onkeyup = function (e) {
    let value = ed_cnd_odrNo.getValue();
    value = value.toUpperCase();          // 소문자 -> 대문자
    value = value.replace(/[^A-Z0-9]/g, ""); // 영문 대문자, 숫자만 허용
    ed_cnd_odrNo.setValue(value);
    if (e.keyCode == 13) scwin.f_Retrieve();
};

