// scwin.gr_cntrInfo_popup

scwin.gr_cntrInfo_ontextimageclick = function (rowIndex, columnIndex) {

    debugger

    let colId = gr_cntrInfo.getColumnID(columnIndex)

    // to-do
    switch (colId) {
        case "portCd":
            scwin.f_openCommPopUpGrid(rowIndex, 'F');
            break;
    }

};

scwin.gr_cntrInfo_oneditend = function (rowIndex, columnIndex, value) {
    debugger
    const colId = this.getColumnID(columnIndex);
    const gridDlt = this._dataList;
    const rowData = gridDlt.getRowJSON(rowIndex);

    switch (colId) {
        case "impWt": //수입중량
            if (value < 0) {
                ds_cntrInfo.setCellData(rowIndex, "impWt", Math.abs(value)); //원래값으로 되돌리기
            };
            break;

        case "expWt": //수출중량
            if (value < 0) {
                ds_cntrInfo.setCellData(rowIndex, "expWt", Math.abs(value)); //원래값으로 되돌리기
            }
            break;

        case "portCd": //팝업
            if (value != "" && value != rowData[colId]) {
                gridDlt.setCellData(rowIndex, colId, "");
                gridDlt.setCellData(rowIndex, 'portNm', "");
                scwin.f_openCommPopUpGrid(rowIndex, 'T', null, value);
            } else if (value == "") {
                gridDlt.setCellData(rowIndex, colId, "");
                gridDlt.setCellData(rowIndex, 'portNm', "");
            }
            break; 

        case "impTemper": //수입온도
        case "expTemper": //수출온도
        case "impTemperCls": //수입온도구분
        case "expTemperCls": //수출온도구분
            scwin.f_SetTemperDryByRFCntr(ds_cntrInfo, gr_cntrInfo, rowIndex);
            break;
    };

};
